// Extract component name from topic: jctsh/<type>/<component>/heartbeat
const parts = msg.topic.split('/');
const component = parts.length >= 3 ? parts[2] : 'unknown';

// Reset the 10-minute timer for this component
const existing = context.get(component + '_timer');
if (existing) clearTimeout(existing);

node.warn('Timer set for ' + component + ' — will fire in 10 min');

const timer = setTimeout(function() {
    context.set(component + '_timer', null);
    node.warn('Timer fired for ' + component);
    node.send({ payload: component });
}, 10 * 60 * 1000);

context.set(component + '_timer', timer);

// No output on receipt — only fires on timeout
return null;

const component = msg.payload;
const HA_URL   = 'http://localhost:8123';
const HA_TOKEN = env.get('HA_TOKEN') || flow.get('haToken') || global.get('haToken');

// Output 1: HA notification request
const haMsg = {
    url: HA_URL + '/api/services/notify/mobile_app_pixel_10_pro_xl',
    method: 'POST',
    headers: {
        'Authorization': 'Bearer ' + HA_TOKEN,
        'Content-Type': 'application/json'
    },
    payload: JSON.stringify({
        message: 'JCTsh alert: ' + component + ' has not reported in 10 minutes',
        title: 'JCTsh Watchdog'
    }),
    _component: component
};

// Output 2: watchdog log message (published regardless of HA result)
const logMsg = {
    payload: JSON.stringify({
        component: 'watchdog',
        category: 'Alert',
        message: 'Component ' + component + ' silent for 10 minutes'
    })
};

return [haMsg, logMsg];

const component = msg._component || 'unknown';
node.warn('HA notify status: ' + msg.statusCode + ' | payload: ' + JSON.stringify(msg.payload));
if (msg.statusCode !== 200 && msg.statusCode !== 201) {
    node.warn('HA notify error ' + msg.statusCode + ': ' + msg.payload);
    return { payload: JSON.stringify({
        component: 'watchdog',
        category: 'Alert',
        message: 'HA notify error ' + msg.statusCode + ' — alert for ' + component + ' may not have delivered'
    })};
}
return null;
